import requests

# RabbitMQ Management API URL and credentials
RABBITMQ_URL = 'http://localhost:15672'
USERNAME = 'admin'
PASSWORD = 'password'

def create_vhost(vhost_name):
    url = f'{RABBITMQ_URL}/api/vhosts/{vhost_name}'
    headers = {'Content-Type': 'application/json'}
    payload = {}
    response = requests.put(url, headers=headers, json=payload, auth=(USERNAME, PASSWORD))
    if response.status_code == 201:
        print(f'Vhost {vhost_name} created successfully.')
    else:
        print(f'Failed to create vhost {vhost_name}. Status code: {response.status_code}')

def set_user_permissions(vhost_name, username):
    url = f'{RABBITMQ_URL}/api/permissions/{vhost_name}/{username}'
    headers = {'Content-Type': 'application/json'}
    payload = {
        "configure": ".*",
        "write": ".*",
        "read": ".*"
    }
    response = requests.put(url, headers=headers, json=payload, auth=(USERNAME, PASSWORD))
    if response.status_code == 201:
        print(f'Permissions set for user {username} on vhost {vhost_name}.')
    else:
        print(f'Failed to set permissions for user {username}. Status code: {response.status_code}')

# Example usage
create_vhost('app1_vhost')
set_user_permissions('app1_vhost', 'user1')

